package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        assertTrue(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set escapeCharacter to null
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);

        // CSVFormat is immutable, so create a new instance by copying all fields except escapeCharacter
        // But since CSVFormat has no public constructor, we set the field directly on the existing instance for test purpose
        // (This breaks immutability but is acceptable in a test)
        escapeCharacterField.set(format, null);

        assertFalse(format.isEscapeCharacterSet());
    }
}
